        const RDWR = 0x002;
        const CREATE = 0x40;
        const TRUNC = 1 << 10;
        const DIRECTORY = 0x0200000;
        const DIR = 0x040000;
        const FILE = 0x100000;
    }
}

impl OpenFlags {
    /// Do not check validity for simplicity
    /// Return (readable, writable)
    pub fn read_write(&self) -> (bool, bool) {
        if self.is_empty() {
            (true, false)
        } else if self.contains(Self::WRONLY) {
            (false, true)
        } else {
            (true, true)
        }
    }
}

