// sys_clone (替代 fork)
pub fn sys_clone(flags: usize, stack_ptr: usize, ...) -> isize {
    let child_process = current_process.fork();
    if stack_ptr != 0 {
        trap_cx.x[2] = stack_ptr;  // 设置子进程栈指针
