// sys_wait4 (阻塞等待)
pub fn sys_wait4(pid: isize, exit_code_ptr: *mut i32, options: isize) -> isize {
    loop {
        // 查找僵尸子进程
        if let Some((idx, child)) = find_zombie_child() {
            *exit_code_ptr = child.exit_code << 8;
            return child.pid;
        } else {
            suspend_current_and_run_next();  // 阻塞等待
        }
    }
}
